# --- radar.py ---
"""Env-faithful trajectory radar for Orbit Wars.

This module predicts where existing fleets and candidate launches will end up.
It mirrors the environment's per-turn fleet movement checks: board bounds, sun
segment crossing, planet segment collision, then moving-planet sweep.
"""


from dataclasses import dataclass
import math
from typing import Optional

BOARD_SIZE = 100.0
CENTER = 50.0
SUN = (CENTER, CENTER)
SUN_RADIUS = 10.0
ROTATION_RADIUS_LIMIT = 50.0
SPAWN_OFFSET = 0.1
DEFAULT_HORIZON = 500
MAX_SPEED = 6.0


@dataclass(frozen=True)
class RadarHit:
    kind: str
    eta: Optional[int] = None
    target_id: Optional[int] = None

    @property
    def hit_planet(self) -> bool:
        return self.kind in ("hit_planet", "swept_planet")


def _get(obs, key, default=None):
    if isinstance(obs, dict):
        return obs.get(key, default)
    return getattr(obs, key, default)


def point_to_segment_distance(point, a, b):
    px, py = point
    ax, ay = a
    bx, by = b
    dx = bx - ax
    dy = by - ay
    denom = dx * dx + dy * dy
    if denom == 0.0:
        return math.hypot(px - ax, py - ay)
    u = max(0.0, min(1.0, ((px - ax) * dx + (py - ay) * dy) / denom))
    cx = ax + u * dx
    cy = ay + u * dy
    return math.hypot(px - cx, py - cy)


def fleet_speed(ships, max_speed=MAX_SPEED):
    if ships <= 1:
        return 1.0
    return 1.0 + (max_speed - 1.0) * (math.log(ships) / math.log(1000)) ** 1.5


def _is_orbiting(initial_planet):
    _pid, _o, ix, iy, r = initial_planet[:5]
    return math.hypot(ix - CENTER, iy - CENTER) + r < ROTATION_RADIUS_LIMIT


def _future_position(initial_planet, current_step, t_ahead, angular_velocity):
    if not _is_orbiting(initial_planet):
        return (initial_planet[2], initial_planet[3])
    _pid, _o, ix, iy = initial_planet[:4]
    dx, dy = ix - CENTER, iy - CENTER
    orbital_radius = math.hypot(dx, dy)
    phase0 = math.atan2(dy, dx)
    phi = phase0 + (current_step + t_ahead - 1) * angular_velocity
    return (
        CENTER + orbital_radius * math.cos(phi),
        CENTER + orbital_radius * math.sin(phi),
    )


class Radar:
    """Trajectory simulator over one observation."""

    def __init__(self, obs, horizon: int = DEFAULT_HORIZON):
        self.obs = obs
        self.horizon = horizon
        self.step = int(_get(obs, "step", 0))
        self.angular_velocity = float(_get(obs, "angular_velocity", 0.0))
        self.planets = [list(p) for p in _get(obs, "planets", []) or []]
        self.initial_planets = [list(p) for p in _get(obs, "initial_planets", []) or []]
        self.comets = [dict(c) for c in _get(obs, "comets", []) or []]
        self.comet_planet_ids = set(_get(obs, "comet_planet_ids", []) or [])

        self.planets_by_id = {p[0]: p for p in self.planets}
        self.initial_by_id = {p[0]: p for p in self.initial_planets}
        self._comet_lookup = self._build_comet_lookup()
        self._pos_cache: dict[tuple[int, int], Optional[tuple[float, float]]] = {}

    def simulate_fleet(self, fleet, horizon: Optional[int] = None) -> RadarHit:
        """Predict the first event for an existing fleet record."""
        return self._simulate(
            x=float(fleet[2]),
            y=float(fleet[3]),
            angle=float(fleet[4]),
            from_planet_id=int(fleet[5]),
            ships=int(fleet[6]),
            horizon=horizon,
        )

    def simulate_launch(
        self,
        src_planet,
        angle: float,
        ships: int,
        horizon: Optional[int] = None,
    ) -> RadarHit:
        """Predict the first event for a newly launched fleet."""
        sx = float(src_planet[2])
        sy = float(src_planet[3])
        sr = float(src_planet[4])
        x = sx + math.cos(angle) * (sr + SPAWN_OFFSET)
        y = sy + math.sin(angle) * (sr + SPAWN_OFFSET)
        return self._simulate(
            x=x,
            y=y,
            angle=float(angle),
            from_planet_id=int(src_planet[0]),
            ships=int(ships),
            horizon=horizon,
        )

    def launch_position(self, src_planet, angle: float) -> tuple[float, float]:
        sx = float(src_planet[2])
        sy = float(src_planet[3])
        sr = float(src_planet[4])
        return (
            sx + math.cos(angle) * (sr + SPAWN_OFFSET),
            sy + math.sin(angle) * (sr + SPAWN_OFFSET),
        )

    def _simulate(
        self,
        x: float,
        y: float,
        angle: float,
        from_planet_id: int,
        ships: int,
        horizon: Optional[int],
    ) -> RadarHit:
        limit = self.horizon if horizon is None else horizon
        limit = max(0, min(int(limit), max(0, 500 - self.step)))
        speed = fleet_speed(ships)
        cx, cy = float(x), float(y)

        for eta in range(1, limit + 1):
            old_pos = (cx, cy)
            cx += math.cos(angle) * speed
            cy += math.sin(angle) * speed
            new_pos = (cx, cy)

            if not (0 <= cx <= BOARD_SIZE and 0 <= cy <= BOARD_SIZE):
                return RadarHit("board", eta=eta)

            if point_to_segment_distance(SUN, old_pos, new_pos) < SUN_RADIUS:
                return RadarHit("sun", eta=eta)

            # Env checks collisions against planet positions before rotation
            # for this turn. Since this Radar starts from an observation at
            # `step`, eta=1 sees planet positions at t_ahead=0.
            for planet in self.planets:
                ppos = self.position_at(planet[0], eta - 1)
                if ppos is None:
                    continue
                if point_to_segment_distance(ppos, old_pos, new_pos) < planet[4]:
                    return RadarHit("hit_planet", eta=eta, target_id=int(planet[0]))

            # Then the env rotates/moves planets and sweeps fleets.
            for planet in self.planets:
                if int(planet[0]) == from_planet_id and eta <= 2:
                    continue
                old_planet_pos = self.position_at(planet[0], eta - 1)
                new_planet_pos = self.position_at(planet[0], eta)
                if old_planet_pos is None or new_planet_pos is None:
                    continue
                if old_planet_pos == new_planet_pos:
                    continue
                if point_to_segment_distance(new_pos, old_planet_pos, new_planet_pos) < planet[4]:
                    return RadarHit("swept_planet", eta=eta, target_id=int(planet[0]))

        return RadarHit("timeout")

    def position_at(self, planet_id: int, t_ahead: int) -> Optional[tuple[float, float]]:
        key = (int(planet_id), int(t_ahead))
        if key in self._pos_cache:
            return self._pos_cache[key]

        planet = self.planets_by_id.get(planet_id)
        if planet is None:
            self._pos_cache[key] = None
            return None

        if planet_id in self.comet_planet_ids:
            pos = self._comet_position_at(planet_id, t_ahead)
        else:
            initial = self.initial_by_id.get(planet_id)
            if initial is None:
                pos = (float(planet[2]), float(planet[3]))
            else:
                pos = _future_position(initial, self.step, t_ahead, self.angular_velocity)

        self._pos_cache[key] = pos
        return pos

    def _build_comet_lookup(self):
        out = {}
        for group in self.comets:
            ids = group.get("planet_ids", []) if isinstance(group, dict) else []
            paths = group.get("paths", []) if isinstance(group, dict) else []
            path_index = group.get("path_index", -1) if isinstance(group, dict) else -1
            for i, pid in enumerate(ids):
                if i < len(paths):
                    out[pid] = (paths[i], path_index)
        return out

    def _comet_position_at(self, planet_id: int, t_ahead: int) -> Optional[tuple[float, float]]:
        planet = self.planets_by_id.get(planet_id)
        entry = self._comet_lookup.get(planet_id)
        if entry is None:
            return (float(planet[2]), float(planet[3])) if t_ahead == 0 else None
        path, path_index = entry
        idx = path_index + int(t_ahead)
        if idx < 0 or idx >= len(path):
            return (float(planet[2]), float(planet[3])) if t_ahead == 0 else None
        return (float(path[idx][0]), float(path[idx][1]))


def simulate_fleet(obs, fleet, horizon: int = DEFAULT_HORIZON) -> RadarHit:
    return Radar(obs, horizon=horizon).simulate_fleet(fleet)


def simulate_launch(obs, src_planet, angle: float, ships: int, horizon: int = DEFAULT_HORIZON) -> RadarHit:
    return Radar(obs, horizon=horizon).simulate_launch(src_planet, angle, ships)

# --- targeting.py ---
"""Pure-math helpers for aiming, threat detection, and ring analysis.

No obstruction checks (sun/planet blockers) yet — kept intentionally simple.
Shared by the human UI (via server endpoints) and by future agents.
"""

import math


SUN = (50.0, 50.0)
SUN_R = 10.0
BOARD = 100.0
MAX_SPEED = 6.0


def fleet_speed(ships, max_speed=MAX_SPEED):
    """Speed per turn for a fleet of N ships (per game's log formula)."""
    if ships <= 1:
        return 1.0
    return 1.0 + (max_speed - 1.0) * (math.log(ships) / math.log(1000)) ** 1.5


def is_orbiting(initial_planet):
    _pid, _o, ix, iy, r = initial_planet[:5]
    return (math.hypot(ix - SUN[0], iy - SUN[1]) + r) < 50.0


def orbit_params(initial_planet):
    """(orbital_radius, phase_at_step_1) for an orbiting planet."""
    _pid, _o, ix, iy = initial_planet[:4]
    dx, dy = ix - SUN[0], iy - SUN[1]
    return math.hypot(dx, dy), math.atan2(dy, dx)


def future_position(initial_planet, current_step, t_ahead, angular_velocity):
    """Where a planet will be at step (current_step + t_ahead).

    Rotation formula (verified empirically): phase = phase0 + (step - 1) * ω.
    """
    if not is_orbiting(initial_planet):
        return (initial_planet[2], initial_planet[3])
    orb_r, phase0 = orbit_params(initial_planet)
    phi = phase0 + (current_step + t_ahead - 1) * angular_velocity
    return (SUN[0] + orb_r * math.cos(phi), SUN[1] + orb_r * math.sin(phi))


def lead_intercept(src_xy, target_initial, ships, angular_velocity, current_step,
                   max_iter=30, tol=0.05):
    """Fixed-point solve for (angle, eta, predicted_pos).

    Source is treated as a stationary point (its current xy). We iterate:
      eta_{n+1} = distance(src, target_pos_at(current_step + eta_n)) / speed.
    Returns dict or None if it fails to converge.
    """
    speed = fleet_speed(ships)
    sx, sy = src_xy
    tx, ty = future_position(target_initial, current_step, 0, angular_velocity)
    eta = max(1.0, math.hypot(tx - sx, ty - sy) / speed)
    converged = False
    for _ in range(max_iter):
        tx, ty = future_position(target_initial, current_step, eta, angular_velocity)
        new_eta = math.hypot(tx - sx, ty - sy) / speed
        if abs(new_eta - eta) < tol:
            eta = new_eta
            converged = True
            break
        eta = new_eta
    if not converged:
        return None
    eta_i = max(1, int(math.ceil(eta)))
    tx, ty = future_position(target_initial, current_step, eta_i, angular_velocity)
    angle = math.atan2(ty - sy, tx - sx)
    return {
        "angle": angle,
        "eta": eta_i,
        "pred_x": tx,
        "pred_y": ty,
        "speed": speed,
    }


def required_ships_to_capture(target_planet, eta):
    """Garrison the target will have at arrival + 1 (ignores other fleets)."""
    ships = target_planet[5]
    prod = target_planet[6]
    return int(ships + prod * eta + 1)


def predict_fleet_landing(fleet, planets, initial_planets, angular_velocity,
                          current_step, max_t=400):
    """Simulate a fleet's straight-line path; return first planet-hit as
    {target_id, eta}, or None if it exits the board or hits the sun.

    Approximation: checks every integer turn. Fast enough for ~50 fleets.
    """
    _fid, _owner, x, y, angle, from_pid, ships = fleet
    speed = fleet_speed(ships)
    vx, vy = math.cos(angle) * speed, math.sin(angle) * speed
    init_by_id = {p[0]: p for p in initial_planets}
    for t in range(1, max_t + 1):
        cx = x + vx * t
        cy = y + vy * t
        if cx < 0 or cx > BOARD or cy < 0 or cy > BOARD:
            return None
        if math.hypot(cx - SUN[0], cy - SUN[1]) < SUN_R:
            return None
        for p in planets:
            pid, _, _, _, pr = p[:5]
            if pid == from_pid and t <= 2:
                continue  # don't re-match source immediately after spawn
            ip = init_by_id.get(pid)
            if ip is None:
                continue
            fx, fy = future_position(ip, current_step, t, angular_velocity)
            if math.hypot(cx - fx, cy - fy) <= pr:
                return {"target_id": pid, "eta": t}
    return None


def threats_per_planet(fleets, planets, initial_planets, angular_velocity, current_step):
    """Map planet_id -> sorted list of {eta, owner, ships, fleet_id} hitting it."""
    obs = {
        "step": current_step,
        "planets": planets,
        "fleets": fleets,
        "initial_planets": initial_planets,
        "angular_velocity": angular_velocity,
        "comets": [],
        "comet_planet_ids": [],
    }
    radar = Radar(obs)
    out = {}
    for f in fleets:
        pred = radar.simulate_fleet(f)
        if not pred.hit_planet:
            continue
        out.setdefault(pred.target_id, []).append({
            "eta": pred.eta,
            "owner": f[1],
            "ships": f[6],
            "fleet_id": f[0],
        })
    for k in out:
        out[k].sort(key=lambda x: x["eta"])
    return out


def ring_order(planets, initial_planets, include_orbiting=False):
    """Planet IDs sorted by polar angle around the sun (CCW from +x axis).

    By default only static outer planets are included. Orbiting planets
    move so their ring position is time-varying; pass include_orbiting=True
    to include them at their current angle.
    """
    init_by_id = {p[0]: p for p in initial_planets}
    entries = []
    for p in planets:
        pid = p[0]
        ip = init_by_id.get(pid)
        if ip is None:
            continue
        if not include_orbiting and is_orbiting(ip):
            continue
        phi = math.atan2(p[3] - SUN[1], p[2] - SUN[0])
        entries.append((phi, pid))
    entries.sort()
    return [pid for _, pid in entries]

class _TargetingNamespace:
    pass

T = _TargetingNamespace()
T.fleet_speed = fleet_speed
T.future_position = future_position

# --- harness_cpu.py ---
"""Dynamic-edge harness for Orbit Wars — CPU inference focus.

Emits variable-length edge tokens (only action-mask-valid edges) instead of
a padded N_max × N_max grid.  One observation in → one ``TokenBundle`` out,
where each token is a single src→tgt launch that has already passed radar
validation under deterministic ship sizing.

Reuses ``radar.py`` and ``targeting.py`` unchanged.

Comets are excluded from consideration in this version — planets listed in
``obs.comet_planet_ids`` are filtered out of the internal planet table.
Re-introduce when we're ready to pay for the extra edges.

Output contract (see ``TokenBundle``):
    edges      (N, 10) float32    per-edge features
    src_ids    (N,) int32         source slot (0..num_planets-1)
    tgt_ids    (N,) int32         target slot
    ships      (N,) int32         deterministic ship count for this edge
    angles     (N,) float32       lead-intercept angle (radians)
    planet_ids (P,) int32         slot → env planet_id

Feature layout (indices are FEATURE_* constants):
    0 eta                  lead-intercept turns to arrival
    1 ships_needed         attackers required to flip tgt at that eta
    2 kind_reinforce       bool: src mine, tgt mine
    3 kind_attack_enemy    bool: src mine, tgt enemy
    4 kind_attack_neutral  bool: src mine, tgt neutral
    5 src_ships            current garrison at src
    6 src_net_threat       enemy_inbound − friendly_inbound at src
    7 tgt_production       tgt production rate
    8 tgt_will_fall        bool: tgt (mine) is projected to flip
    9 src_can_fund         bool: source ships >= harness-computed need
   10 turns_left           episode turns remaining (broadcast scalar)
"""


import math
from dataclasses import dataclass
from typing import Optional

import numpy as np



BOARD = 100.0
SUN = (50.0, 50.0)
SUN_R = 10.0
EPISODE_STEPS = 500

# Feature indices — stable, use these never the raw ints.
FEATURE_ETA = 0
FEATURE_SHIPS_NEEDED = 1
FEATURE_KIND_REINFORCE = 2
FEATURE_KIND_ATTACK_ENEMY = 3
FEATURE_KIND_ATTACK_NEUTRAL = 4
FEATURE_SRC_SHIPS = 5
FEATURE_SRC_NET_THREAT = 6
FEATURE_TGT_PRODUCTION = 7
FEATURE_TGT_WILL_FALL = 8
FEATURE_SRC_CAN_FUND = 9
FEATURE_TURNS_LEFT = 10
FEATURE_DIM = 11

FEATURE_NAMES = [
    "eta", "ships_needed",
    "kind_reinforce", "kind_attack_enemy", "kind_attack_neutral",
    "src_ships", "src_net_threat",
    "tgt_production", "tgt_will_fall", "src_can_fund",
    "turns_left",
]

FEATURE_SCALES = np.array([
    50.0,   # eta
    100.0,  # ships_needed
    1.0, 1.0, 1.0,
    100.0,  # src_ships
    50.0,   # src_net_threat
    5.0,    # tgt_production
    1.0,
    1.0,    # src_can_fund
    500.0,  # turns_left
], dtype=np.float32)


def _get(obs, key, default=None):
    if isinstance(obs, dict):
        return obs.get(key, default)
    return getattr(obs, key, default)


def _point_to_segment_distance(point, a, b):
    px, py = point
    ax, ay = a
    bx, by = b
    dx = bx - ax
    dy = by - ay
    denom = dx * dx + dy * dy
    if denom == 0.0:
        return math.hypot(px - ax, py - ay)
    u = max(0.0, min(1.0, ((px - ax) * dx + (py - ay) * dy) / denom))
    cx = ax + u * dx
    cy = ay + u * dy
    return math.hypot(px - cx, py - cy)


@dataclass
class TokenBundle:
    """Packed edge tokens for a single observation."""

    edges: np.ndarray        # (N, FEATURE_DIM) float32
    src_ids: np.ndarray      # (N,) int32 — slot index into planet_ids
    tgt_ids: np.ndarray      # (N,) int32 — slot index into planet_ids
    ships: np.ndarray        # (N,) int32
    angles: np.ndarray       # (N,) float32
    planet_ids: np.ndarray   # (P,) int32 — slot → env planet_id

    @property
    def n(self) -> int:
        return int(self.edges.shape[0])

    @property
    def num_planets(self) -> int:
        return int(self.planet_ids.shape[0])


class GameView_CPU:
    """Observation wrapped as variable-length edge tokens.

    Comets are dropped — this view only considers permanent planets.
    """

    def __init__(self, obs, safety_margin: int = 1):
        self.safety_margin = int(safety_margin)
        self._radar: Optional[Radar] = None
        self._fleet_predictions: dict[int, RadarHit] = {}
        self._tokens: Optional[TokenBundle] = None
        self._tokens_dirty = True
        self._absorb_obs(obs)
        self._populate_all_fleet_predictions()
        self.threats = self._rebuild_threats_from_predictions()

    # ------------------------------------------------------------------
    # State ingestion
    # ------------------------------------------------------------------

    def _absorb_obs(self, obs):
        """Copy planets / fleets / scalars from obs, filter out comets."""
        self.obs = obs
        self.player = int(_get(obs, "player", 0))
        self.step = int(_get(obs, "step", 0))
        self.turns_left = max(0, EPISODE_STEPS - self.step)
        self.angular_velocity = float(_get(obs, "angular_velocity", 0.0))

        comet_ids = set(_get(obs, "comet_planet_ids", []) or [])
        raw_planets = _get(obs, "planets", []) or []
        self.planets = [list(p) for p in raw_planets if p[0] not in comet_ids]
        self.planets_by_id = {p[0]: p for p in self.planets}

        raw_initial = _get(obs, "initial_planets", []) or []
        self.initial_planets = [list(p) for p in raw_initial if p[0] not in comet_ids]
        self.initial_by_id = {p[0]: p for p in self.initial_planets}

        self.fleets = [list(f) for f in _get(obs, "fleets", []) or []]
        self.next_fleet_id = int(_get(obs, "next_fleet_id", 0) or 0)

        self._num_planets = len(self.planets)
        self._planet_ids_array = np.array(
            [p[0] for p in self.planets], dtype=np.int32
        )
        self._slot_of: dict[int, int] = {p[0]: i for i, p in enumerate(self.planets)}

        # New obs → planets may have rotated → radar cache is stale.
        self._radar = None

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def tokens(self) -> TokenBundle:
        if self._tokens_dirty or self._tokens is None:
            self._tokens = self._build_tokens()
            self._tokens_dirty = False
        return self._tokens

    def decode_action(self, token_idx: int) -> Optional[list]:
        """Convert a token index to ``[from_planet_id, angle, num_ships]``."""
        bundle = self.tokens()
        if not (0 <= token_idx < bundle.n):
            return None
        src_slot = int(bundle.src_ids[token_idx])
        src_pid = int(bundle.planet_ids[src_slot])
        return [src_pid, float(bundle.angles[token_idx]), int(bundle.ships[token_idx])]

    def apply_planned_move(self, token_idx: int) -> Optional[list]:
        """Mutate the view to reflect a same-turn launch of the given token.

        Returns the resolved ``[src_pid, angle, ships]`` action, or None if
        the token index is invalid / radar rejects the launch.  On success:

          * ``self.planets``: src garrison drops by ``ships``
          * ``self.fleets``: planned fleet appended (so future projections see it)
          * ``self.threats[tgt_pid]``: planned fleet's predicted landing inserted
          * ``self._fleet_predictions[planned_id]``: stored for cross-turn reuse
          * tokens are marked dirty; next ``tokens()`` call rebuilds
        """
        bundle = self.tokens()
        if not (0 <= token_idx < bundle.n):
            return None
        src_slot = int(bundle.src_ids[token_idx])
        tgt_slot = int(bundle.tgt_ids[token_idx])
        src_pid = int(bundle.planet_ids[src_slot])
        tgt_pid = int(bundle.planet_ids[tgt_slot])
        angle = float(bundle.angles[token_idx])
        ships = int(bundle.ships[token_idx])

        src = self.planets_by_id.get(src_pid)
        if src is None or src[5] < ships or ships <= 0:
            return None

        radar = self._get_radar()
        hit = radar.simulate_launch(src, angle, ships)
        if not (hit.hit_planet and hit.target_id == tgt_pid):
            return None
        launch_xy = radar.launch_position(src, angle)

        # Apply state deltas.
        src[5] = int(src[5]) - ships
        planned_id = self.next_fleet_id
        self.next_fleet_id += 1
        planned_fleet = [
            planned_id, int(self.player),
            float(launch_xy[0]), float(launch_xy[1]),
            float(angle), src_pid, ships,
        ]
        self.fleets.append(planned_fleet)
        self._fleet_predictions[planned_id] = hit
        self.threats.setdefault(tgt_pid, []).append({
            "eta": int(hit.eta),
            "owner": int(self.player),
            "ships": int(ships),
            "fleet_id": int(planned_id),
        })
        self.threats[tgt_pid].sort(key=lambda t: t["eta"])

        self._tokens_dirty = True
        return [src_pid, angle, ships]

    def update_from_obs(self, new_obs):
        """Advance to next turn; reuse carry-over fleet predictions."""
        old_step = self.step
        new_step = int(_get(new_obs, "step", old_step + 1))
        steps_advanced = max(1, new_step - old_step)
        old_predictions = dict(self._fleet_predictions)

        self._absorb_obs(new_obs)

        # Diff fleets: carry-overs reuse prediction with eta decremented;
        # new ones get a fresh simulate_fleet.
        radar = self._get_radar()
        self._fleet_predictions.clear()
        for f in self.fleets:
            fid = int(f[0])
            old_hit = old_predictions.get(fid)
            if (old_hit is not None
                    and old_hit.hit_planet
                    and old_hit.eta is not None
                    and (old_hit.eta - steps_advanced) >= 1):
                self._fleet_predictions[fid] = RadarHit(
                    kind=old_hit.kind,
                    eta=old_hit.eta - steps_advanced,
                    target_id=old_hit.target_id,
                )
            else:
                self._fleet_predictions[fid] = radar.simulate_fleet(f)

        self.threats = self._rebuild_threats_from_predictions()
        self._tokens_dirty = True

    # ------------------------------------------------------------------
    # Token construction
    # ------------------------------------------------------------------

    def _build_tokens(self) -> TokenBundle:
        # Per-planet scalar caches.
        tgt_info = [self._compute_tgt_info(i) for i in range(self._num_planets)]
        src_info = [self._compute_src_info(i) for i in range(self._num_planets)]

        edges_list: list[np.ndarray] = []
        src_ids_list: list[int] = []
        tgt_ids_list: list[int] = []
        ships_list: list[int] = []
        angles_list: list[float] = []

        radar = self._get_radar()
        for src_slot, src in enumerate(self.planets):
            if src[1] != self.player or src[5] <= 0:
                continue
            for tgt_slot, tgt in enumerate(self.planets):
                if src_slot == tgt_slot:
                    continue
                tok = self._try_build_token(
                    src_slot, src, tgt_slot, tgt,
                    src_info[src_slot], tgt_info[tgt_slot], radar,
                )
                if tok is None:
                    continue
                features, ships, angle = tok
                edges_list.append(features)
                src_ids_list.append(src_slot)
                tgt_ids_list.append(tgt_slot)
                ships_list.append(ships)
                angles_list.append(angle)

        if edges_list:
            edges = np.stack(edges_list, axis=0).astype(np.float32, copy=False)
        else:
            edges = np.zeros((0, FEATURE_DIM), dtype=np.float32)
        return TokenBundle(
            edges=edges,
            src_ids=np.asarray(src_ids_list, dtype=np.int32),
            tgt_ids=np.asarray(tgt_ids_list, dtype=np.int32),
            ships=np.asarray(ships_list, dtype=np.int32),
            angles=np.asarray(angles_list, dtype=np.float32),
            planet_ids=self._planet_ids_array,
        )

    def _try_build_token(self, src_slot, src, tgt_slot, tgt,
                         src_info, tgt_info, radar):
        """Return (features, ships, angle) if the edge is mask-valid, else None."""
        _, _, sx, sy, src_r, src_ships_avail, _ = src
        tgt_pid = tgt[0]
        tgt_owner = tgt[1]

        src_ships_int = int(src_ships_avail)
        ships = max(1, src_ships_int)
        intercept = None
        eta = None
        ships_needed_f = 1.0
        need = 1

        # Fleet speed depends on ships, and attack need depends on ETA. Iterate
        # until the token's ETA, ships_needed, and deterministic ships agree.
        for _ in range(6):
            intercept = self._lead_intercept((sx, sy), tgt_pid, ships, src_radius=src_r)
            if intercept is None:
                return None
            eta = int(intercept["eta"])

            future_garrison = self._project_garrison(tgt_pid, eta)
            if tgt_owner == self.player:
                ships_needed_f = (
                    max(1.0, float(-future_garrison)) if future_garrison < 0 else 1.0
                )
            else:
                defender = -future_garrison if future_garrison < 0 else future_garrison
                ships_needed_f = max(1.0, float(defender) + 1.0)

            if tgt_owner == self.player:
                flip_eta = self.first_flip_eta(tgt_pid)
                if flip_eta is None:
                    need = 1
                else:
                    deficit = -self._project_garrison(tgt_pid, flip_eta)
                    need = max(1, int(math.ceil(deficit)) + self.safety_margin)
            else:
                need = max(1, int(math.ceil(ships_needed_f)) + self.safety_margin)

            next_ships = min(src_ships_int, need)
            if next_ships <= 0:
                return None
            if next_ships == ships:
                break
            ships = next_ships

        if intercept is None or eta is None:
            return None

        if not self._sun_crossing_clear((sx, sy), intercept):
            return None

        src_can_fund = src_ships_int >= need
        final_angle = float(intercept["angle"])

        # Radar-validate: the launched fleet's first hit must be tgt_pid.
        hit = radar.simulate_launch(src, final_angle, ships)
        if not (hit.hit_planet and hit.target_id == tgt_pid):
            return None

        # Feature vector.
        f = np.zeros(FEATURE_DIM, dtype=np.float32)
        f[FEATURE_ETA] = eta
        f[FEATURE_SHIPS_NEEDED] = ships_needed_f
        if tgt_owner == self.player:
            f[FEATURE_KIND_REINFORCE] = 1.0
        elif tgt_owner == -1:
            f[FEATURE_KIND_ATTACK_NEUTRAL] = 1.0
        else:
            f[FEATURE_KIND_ATTACK_ENEMY] = 1.0
        f[FEATURE_SRC_SHIPS] = src_info["ships"]
        f[FEATURE_SRC_NET_THREAT] = src_info["net_threat"]
        f[FEATURE_TGT_PRODUCTION] = tgt_info["production"]
        f[FEATURE_TGT_WILL_FALL] = 1.0 if tgt_info["will_fall"] else 0.0
        f[FEATURE_SRC_CAN_FUND] = 1.0 if src_can_fund else 0.0
        f[FEATURE_TURNS_LEFT] = float(self.turns_left)
        return f, int(ships), final_angle

    def _compute_tgt_info(self, slot: int) -> dict:
        planet = self.planets[slot]
        return {
            "production": float(planet[6]),
            "will_fall": self._will_fall_if_ignored(planet[0]),
        }

    def _compute_src_info(self, slot: int) -> dict:
        planet = self.planets[slot]
        return {
            "ships": float(planet[5]),
            "net_threat": self._net_threat_at(planet[0]),
        }

    # ------------------------------------------------------------------
    # Radar / threat bookkeeping
    # ------------------------------------------------------------------

    def _get_radar(self) -> Radar:
        if self._radar is None:
            self._radar = Radar(self.obs)
        return self._radar

    def _populate_all_fleet_predictions(self):
        radar = self._get_radar()
        self._fleet_predictions.clear()
        for f in self.fleets:
            self._fleet_predictions[int(f[0])] = radar.simulate_fleet(f)

    def _rebuild_threats_from_predictions(self) -> dict:
        threats: dict[int, list[dict]] = {}
        for f in self.fleets:
            fid = int(f[0])
            hit = self._fleet_predictions.get(fid)
            if hit is None or not hit.hit_planet:
                continue
            threats.setdefault(int(hit.target_id), []).append({
                "eta": int(hit.eta),
                "owner": int(f[1]),
                "ships": int(f[6]),
                "fleet_id": fid,
            })
        for entries in threats.values():
            entries.sort(key=lambda t: t["eta"])
        return threats

    # ------------------------------------------------------------------
    # Geometry
    # ------------------------------------------------------------------

    def _lead_intercept(self, src_xy, tgt_pid, ships, src_radius=None,
                        max_iter=30, tol=0.05):
        speed = T.fleet_speed(ships)
        sx, sy = src_xy
        pos = self._position_at(tgt_pid, 0)
        if pos is None:
            return None
        angle = math.atan2(pos[1] - sy, pos[0] - sx)
        launch = self._launch_point((sx, sy), src_radius, angle)
        eta = max(1.0, math.hypot(pos[0] - launch[0], pos[1] - launch[1]) / speed)
        converged = False
        for _ in range(max_iter):
            pos = self._position_at(tgt_pid, int(math.ceil(eta)))
            if pos is None:
                return None
            launch = self._launch_point((sx, sy), src_radius, angle)
            new_angle = math.atan2(pos[1] - launch[1], pos[0] - launch[0])
            new_launch = self._launch_point((sx, sy), src_radius, new_angle)
            new_eta = math.hypot(pos[0] - new_launch[0], pos[1] - new_launch[1]) / speed
            if abs(new_eta - eta) < tol:
                eta = new_eta
                angle = new_angle
                converged = True
                break
            eta = new_eta
            angle = new_angle
        if not converged:
            return None
        eta_i = max(1, int(math.ceil(eta)))
        pos = self._position_at(tgt_pid, eta_i)
        if pos is None:
            return None
        launch = self._launch_point((sx, sy), src_radius, angle)
        angle = math.atan2(pos[1] - launch[1], pos[0] - launch[0])
        return {"angle": angle, "eta": eta_i,
                "pred_x": pos[0], "pred_y": pos[1], "speed": speed}

    def _launch_point(self, src_xy, src_radius, angle):
        if src_radius is None:
            return src_xy
        return (
            src_xy[0] + math.cos(angle) * (float(src_radius) + 0.1),
            src_xy[1] + math.sin(angle) * (float(src_radius) + 0.1),
        )

    def _position_at(self, planet_id, t_ahead):
        planet = self.planets_by_id.get(planet_id)
        if planet is None:
            return None
        initial = self.initial_by_id.get(planet_id)
        if initial is None:
            return (planet[2], planet[3])
        return T.future_position(initial, self.step, t_ahead, self.angular_velocity)

    def _sun_crossing_clear(self, src_xy, intercept):
        end = (intercept["pred_x"], intercept["pred_y"])
        return _point_to_segment_distance(SUN, src_xy, end) >= SUN_R

    # ------------------------------------------------------------------
    # Threat projections
    # ------------------------------------------------------------------

    def _project_garrison(self, planet_id, horizon):
        """Signed garrison at step + horizon under known inbound fleets."""
        planet = self.planets_by_id.get(planet_id)
        if planet is None:
            return 0
        owner = planet[1]
        ships = int(planet[5])
        prod = int(planet[6])
        arrivals = sorted(self.threats.get(planet_id, []), key=lambda t: t["eta"])
        last_t = 0
        for ar in arrivals:
            eta = ar["eta"]
            if eta > horizon:
                break
            if owner != -1:
                ships += prod * max(0, eta - last_t)
            if ar["owner"] == owner:
                ships += ar["ships"]
            else:
                ships -= ar["ships"]
                if ships < 0:
                    owner = ar["owner"]
                    ships = abs(ships)
            last_t = eta
        if owner != -1:
            ships += prod * max(0, horizon - last_t)
        return ships if owner == self.player else -ships

    def _will_fall_if_ignored(self, planet_id):
        planet = self.planets_by_id.get(planet_id)
        if planet is None or planet[1] != self.player:
            return False
        ships = int(planet[5])
        prod = int(planet[6])
        owner = planet[1]
        last_t = 0
        for ar in sorted(self.threats.get(planet_id, []), key=lambda t: t["eta"]):
            eta = ar["eta"]
            ships += prod * max(0, eta - last_t)
            if ar["owner"] == owner:
                ships += ar["ships"]
            else:
                ships -= ar["ships"]
                if ships < 0:
                    return True
            last_t = eta
        return False

    def first_flip_eta(self, planet_id):
        planet = self.planets_by_id.get(planet_id)
        if planet is None or planet[1] != self.player:
            return None
        ships = int(planet[5])
        prod = int(planet[6])
        owner = planet[1]
        last_t = 0
        for ar in sorted(self.threats.get(planet_id, []), key=lambda t: t["eta"]):
            eta = ar["eta"]
            ships += prod * max(0, eta - last_t)
            if ar["owner"] == owner:
                ships += ar["ships"]
            else:
                ships -= ar["ships"]
                if ships < 0:
                    return eta
            last_t = eta
        return None

    def _net_threat_at(self, planet_id):
        total = 0
        for ar in self.threats.get(planet_id, []):
            if ar["owner"] == self.player:
                total -= ar["ships"]
            else:
                total += ar["ships"]
        return float(total)


